local LBattleBuffActBase = require("LApp.gameplay.videobattle.view.buffact.LBattleBuffActBase")
---@class LBattleBuffActEffect:LBattleBuffActBase
local LBattleBuffActEffect = classX("LBattleBuffActEffect",LBattleBuffActBase)

function LBattleBuffActEffect:ctor(viewMgr)
    LBattleBuffActBase.ctor(self, viewMgr)
    self._type = LSkillEffConst.PLAY_EFF_EFFECT
end

function LBattleBuffActEffect:Preload()
    LBattleBuffActBase.Preload(self)
end

function LBattleBuffActEffect:OnStart()
    local effData = self._effData
    local effRes = effData.effRes --光效名字
    local playTime = effData.playTime --光效持续时间
    local dissipateTime = effData.dissipateTime --光效消散时间
    local offset = effData.effOffsetStart --偏移
    --local excursionIObject = effData.excursionIObject

    local offsetX = offset.x
    local offsetY = offset.y
    local dataList = self._runningData.dataList
    --local scale = self._runningData.scale
    local isUpperLayer = self._runningData.isUpperLayer
    --local bulletTarPos = self._runningData.bulletTarPos

    local effectCtrl = self._viewMgr:GetEffectCtrl()
    for k, v in ipairs(dataList) do
        local rootTrans = v.trans
        local pos = v.pos
        local dir = v.dir

        if dir == LFightConst.DIRECTION_LEFT then
            pos.x = pos.x - offsetX
        else
            pos.x = pos.x + offsetX
        end
        pos.y = pos.y + offsetY
        pos.z = 0

        ---根据子弹落点
        --if excursionIObject == 1 and bulletTarPos then
        --    pos = bulletTarPos
        --    pos.z = 0
        --end

        local effect = effectCtrl:MakeEffectObject(rootTrans, effRes, pos, dir, 0, playTime,dissipateTime)
        local para =
        {
            isUpperLayer= isUpperLayer,
            scale = 1
        }
        effect:SetEffectPara(para)
        effectCtrl:AddEffect(effect)
    end
end



return LBattleBuffActEffect